+  if (auto *CondSel = dyn_cast<SelectInst>(CondVal)) {
+    Value *X = CondSel->getCondition();
+    if (auto *Sel = dyn_cast<SelectInst>(FalseVal)) {
+      if (
+          Sel->getCondition() == X &&
+          match(CondSel->getFalseValue(), m_Zero()) &&
+          CondSel->getType()->isIntOrIntVectorTy(1)) {
+        Value *Y = CondSel->getTrueValue();
+        Value *A = Sel->getTrueValue();
+        Value *B = Sel->getFalseValue();
+        Value *InnerSel = Builder.CreateSelect(Y, TrueVal, A);
+        return SelectInst::Create(X, InnerSel, B);
+      }
+    }
+    if (auto *Sel = dyn_cast<SelectInst>(TrueVal)) {
+      if (
+          Sel->getCondition() == X &&
+          match(CondSel->getTrueValue(), m_One()) &&
+          CondSel->getType()->isIntOrIntVectorTy(1)) {
+        Value *Y = CondSel->getFalseValue();
+        Value *A = Sel->getTrueValue();
+        Value *B = Sel->getFalseValue();
+        Value *InnerSel = Builder.CreateSelect(Y, B, FalseVal);
+        return SelectInst::Create(X, A, InnerSel);
+      }
+    }
+  }
